// VAPI Provider Configuration
// Based on official VAPI documentation and API specifications

export interface ModelProvider {
  id: string;
  name: string;
  models: ModelOption[];
  defaultModel?: string;
  description?: string;
  requiresApiKey?: boolean;
}

export interface ModelOption {
  id: string;
  name: string;
  description?: string;
  maxTokens?: number;
  supportsTools?: boolean;
  supportsVision?: boolean;
  costTier?: 'low' | 'medium' | 'high';
}

export interface VoiceProvider {
  id: string;
  name: string;
  voices: VoiceOption[];
  defaultVoice?: string;
  description?: string;
  requiresApiKey?: boolean;
  supportsSpeed?: boolean;
  supportsStability?: boolean;
  supportsSimilarityBoost?: boolean;
}

export interface VoiceOption {
  id: string;
  name: string;
  gender?: 'male' | 'female' | 'neutral';
  accent?: string;
  language?: string;
  description?: string;
  preview?: string;
}

export interface TranscriberProvider {
  id: string;
  name: string;
  models: TranscriberModel[];
  defaultModel?: string;
  description?: string;
  requiresApiKey?: boolean;
  supportsLanguages?: string[];
}

export interface TranscriberModel {
  id: string;
  name: string;
  description?: string;
  accuracy?: 'standard' | 'enhanced' | 'premium';
  latency?: 'low' | 'medium' | 'high';
}

