// Helper functions
export const getProviderModels = (providerId: string): ModelOption[] => {
  const provider = MODEL_PROVIDERS.find(p => p.id === providerId);
  return provider?.models || [];
};

export const getProviderVoices = (providerId: string): VoiceOption[] => {
  const provider = VOICE_PROVIDERS.find(p => p.id === providerId);
  return provider?.voices || [];
};

export const getTranscriberModels = (providerId: string): TranscriberModel[] => {
  const provider = TRANSCRIBER_PROVIDERS.find(p => p.id === providerId);
  return provider?.models || [];
};

export const getDefaultModel = (providerId: string): string => {
  const provider = MODEL_PROVIDERS.find(p => p.id === providerId);
  return provider?.defaultModel || provider?.models[0]?.id || '';
};

export const getDefaultVoice = (providerId: string): string => {
  const provider = VOICE_PROVIDERS.find(p => p.id === providerId);
  return provider?.defaultVoice || provider?.voices[0]?.id || '';
};

export const getDefaultTranscriberModel = (providerId: string): string => {
  const provider = TRANSCRIBER_PROVIDERS.find(p => p.id === providerId);
  return provider?.defaultModel || provider?.models[0]?.id || '';
};
